import React, { useEffect, useState } from "react";
import heroImage from "../../assets/hero-image.jpg";
import logo from "../../assets/up-text-icon.jpg";

const Home = ({ onGetStarted, onLoginClick }) => {

  const [showHeader, setShowHeader] = useState(true);
  const [lastY, setLastY] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      setShowHeader(window.scrollY < lastY || window.scrollY < 60);
      setLastY(window.scrollY);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, [lastY]);

  return (
    <div style={{ fontFamily: "system-ui, sans-serif", background: "#f9fafb", color: "#111827" }}>

      {/* HEADER */}
      <header
        style={{
          position: "sticky",
          top: 0,
          zIndex: 1000,
          background: "#fbbf24",
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          padding: "16px 48px",
          transition: "opacity 0.3s",
          opacity: showHeader ? 1 : 0
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <img src={logo} alt="Logo" style={{ height: 48, borderRadius: 12 }} />
          <div style={{ fontSize: 32, fontWeight: 900 }}>SHIFT-UP</div>
        </div>

        <div style={{ display: "flex", alignItems: "center", gap: 20 }}>
          <a href="#features" style={{ textDecoration: "none", color: "#111" }}>Features</a>
          <a href="#pricing" style={{ textDecoration: "none", color: "#111" }}>Pricing</a>
          <a href="#about" style={{ textDecoration: "none", color: "#111" }}>About</a>

          <button
            onClick={onLoginClick}
            style={{ padding: "8px 16px", borderRadius: 999, border: "1px solid #111", background: "transparent", cursor: "pointer" }}
          >
            Login
          </button>

          <button
            onClick={onGetStarted}
            style={{ padding: "8px 16px", borderRadius: 999, border: "none", background: "#111", color: "#fff", cursor: "pointer" }}
          >
            Get Started
          </button>
        </div>
      </header>

      {/* HERO */}
      <section
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: 32,
          alignItems: "center",
          padding: "56px 64px",
          background: "#fff"
        }}
      >
        <div>
          <h1 style={{ fontSize: 40, marginBottom: 12 }}>
            Elevate Your Business into the Future
          </h1>

          <p style={{ color: "#6b7280", marginBottom: 20 }}>
            Accelerate, Optimize, Transform — seamless shift scheduling for modern teams.
          </p>

          <button
            onClick={onGetStarted}
            style={{ padding: "10px 20px", borderRadius: 999, border: "none", background: "#111", color: "#fff", cursor: "pointer" }}
          >
            Get Started
          </button>
        </div>

        <img src={heroImage} alt="Hero" style={{ width: "100%", borderRadius: 12 }} />
      </section>

      {/* INTRO */}
      <section id="features" style={{ padding: "24px 64px", maxWidth: 900, margin: "0 auto", color: "#4b5563" }}>
        <p>
          With ShiftUp, experience a seamless flow from scheduling to payday.
          Manage every shift effortlessly with a system designed to streamline staff scheduling.
        </p>
      </section>

      {/* FEATURES */}
      <section style={{ padding: "16px 64px 40px", display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(260px,1fr))", gap: 16 }}>
        {[
          "Scheduling",
          "Reports & Analytics",
          "Shift Swap",
          "Manager Approvals",
          "Smart Notifications",
          "Manager Dashboard"
        ].map(f => (
          <div key={f} style={{ background: "#fff", padding: 20, borderRadius: 10, boxShadow: "0 1px 2px rgba(0,0,0,0.05)" }}>
            <h3>{f}</h3>
          </div>
        ))}
      </section>

      {/* PRICING */}
      <section id="pricing" style={{ padding: "32px 64px", textAlign: "center", background: "#fff" }}>
        <div style={{ background: "#111", color: "#fff", padding: 24, borderRadius: 16, maxWidth: 360, margin: "0 auto" }}>
          <div style={{ fontSize: 32, fontWeight: 700 }}>$5/mo</div>

          <ul style={{ textAlign: "left", marginTop: 16 }}>
            <li>Employee scheduling</li>
            <li>Shift swap requests</li>
            <li>Notifications</li>
            <li>Dashboard</li>
          </ul>

          <button
            onClick={onGetStarted}
            style={{ marginTop: 16, padding: "10px 20px", borderRadius: 999, border: "none", background: "#fff", cursor: "pointer" }}
          >
            Get Started
          </button>
        </div>
      </section>

      {/* ABOUT */}
      <section id="about" style={{ padding: "60px 40px" }}>
        <h2>About ShiftUp</h2>
        <p>
          At ShiftUp, we believe in empowering businesses with smarter workforce tools.
        </p>
      </section>

    </div>
  );
};

export default Home;
